; EarthBound C2 crying status action.
;
; Source-emission status:
; - Prototype level: build-candidate
; - Generated by tools/emit_linear_source_module.py from a state-aware
;   linear ROM decode, then intended for byte-equivalence validation.
;
; Source units covered:
; - C2:8C69..C2:8CB8 RunCryingStatusAction
;
; Runtime contract:
; - Late action-table status body for the `+0x1F` temporary subgroup.
; - Gates through `C2:7CFD`, then tests selected-row byte `+0x39` through
;   `C2:6BB8`.
; - Calls the generic affliction writer with `Y = 2`, `X = 2`, targeting
;   selected-row byte `+0x1F`.
; - Emits `EF:6BBB` on success and shared no-effect text `EF:766E` on failure.

; ---------------------------------------------------------------------------
; External contracts used by this module

C26BB8_RollActionChanceGate                   = $6BB8
C2724A_ApplySelectedRowAfflictionSlotValue    = $724A
C27CFD_CheckSelectedBattlerDefaultTextBlocker = $7CFD
C1DC1C_DisplayBattleTextFromPointer           = $C1DC1C
EFMSG_CryingInflicted                         = $6BBB
EFMSG_StatusNoEffect                          = $766E

; ---------------------------------------------------------------------------
; C2:8C69

BTLACT_CRYING:
C28C69_RunCryingStatusAction = BTLACT_CRYING
    rep #$31
    phd
    tdc
    adc.w #$FFEE
    tcd
    jsr C27CFD_CheckSelectedBattlerDefaultTextBlocker
    cmp.w #$0000
    bne C28CB6_RunCryingStatusAction_L8CB6
    ldx $A972
    sep #$20
    lda $0039,X
    ; Extra selected-row gate before crying can be installed.
    jsr C26BB8_RollActionChanceGate
    cmp.w #$0000
    beq C28CA8_RunCryingStatusAction_L8CA8
    ldy.w #$0002
    tyx
    ; Write temporary subgroup `+0x1F = 2`.
    lda $A972
    jsr C2724A_ApplySelectedRowAfflictionSlotValue
    cmp.w #$0000
    beq C28CA8_RunCryingStatusAction_L8CA8
    ; Success/failure EF scripts both read the target-name battle text context.
    lda.w #EFMSG_CryingInflicted
    sta $0E
    lda.w #$00EF
    sta $10
    jsl C1DC1C_DisplayBattleTextFromPointer
    bra C28CB6_RunCryingStatusAction_L8CB6
C28CA8_RunCryingStatusAction_L8CA8:
    lda.w #EFMSG_StatusNoEffect
    sta $0E
    lda.w #$00EF
    sta $10
    jsl C1DC1C_DisplayBattleTextFromPointer
C28CB6_RunCryingStatusAction_L8CB6:
    pld
    rtl
